def generate_api_key(user_id: str) -> str:
    """Generate a secure API key for a user."""
    key = secrets.token_urlsafe(32)
    key_hash = hashlib.sha256(key.encode()).hexdigest()
    api_keys[key_hash] = {
        'user_id': user_id,
        'active': True
    }
    return key


def verify_api_key(key: str) -> Optional[dict]:
    """Verify an API key and return user info."""
    key_hash = hashlib.sha256(key.encode()).hexdigest()
    info = api_keys.get(key_hash)
    if info and info['active']:
        return info
    return None


def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            return jsonify({'error': 'Missing API key'}), 401

        user_info = verify_api_key(api_key)
        if not user_info:
            return jsonify({'error': 'Invalid API key'}), 403

        g.user_id = user_info['user_id']
        return f(*args, **kwargs)
    return decorated


def rate_limit(f):
    """Simple rate limiting decorator."""
    @wraps(f)
    def decorated(*args, **kwargs):
        import time
        user_id = getattr(g, 'user_id', request.remote_addr)
        now = time.time()
        window_start = now - 60

        if user_id not in rate_limit_store:
            rate_limit_store[user_id] = []

        # Clean old entries
        rate_limit_store[user_id] = [
            t for t in rate_limit_store[user_id] if t > window_start
        ]

        if len(rate_limit_store[user_id]) >= app.config['RATE_LIMIT_PER_MINUTE']:
            return jsonify({'error': 'Rate limit exceeded'}), 429

        rate_limit_store[user_id].append(now)
        return f(*args, **kwargs)
    return decorated


def allowed_file(filename: str, allowed_extensions: set) -> bool:
    """Check if file extension is allowed."""
    if not filename or '.' not in filename:
        return False
    ext = filename.rsplit('.', 1)[1].lower()
    return ext in allowed_extensions


def sanitize_filename(filename: str) -> str:
    """Sanitize filename to prevent path traversal."""
    filename = secure_filename(filename)
    if not filename:
        filename = f"upload_{uuid.uuid4().hex}"
    return filename


def validate_csv_data(filepath: str) -> tuple:
    """
    Validate and sanitize CSV data.
    Returns (dataframe, error_message).
    """
    try:
        # Read with limited rows to prevent memory exhaustion
        df = pd.read_csv(
            filepath,
            nrows=app.config['MAX_ROWS_PER_CSV'],
            na_values=[''],
            keep_default_na=True
        )
    except Exception as e:
        logger.warning(f"Failed to parse CSV: {e}")
        return None, "Invalid CSV format"

    if df.empty:
        return None, "CSV file is empty"

    # Check required columns
    required_columns = {'image_path', 'label'}
    if not required_columns.issubset(set(df.columns)):
        return None, f"CSV must contain columns: {required_columns}"

    # Validate labels - must be alphanumeric strings
    df['label'] = df['label'].astype(str).str.strip()
    label_pattern = re.compile(r'^[a-zA-Z0-9_\-\s]{1,100}$')
    invalid_labels = df[~df['label'].apply(lambda x: bool(label_pattern.match(x)))]
    if not invalid_labels.empty:
        return None, "Labels must be alphanumeric (max 100 chars)"

    # Check number of unique classes
    num_classes = df['label'].nunique()
    if num_classes > app.config['MAX_CLASSES']:
        return None, f"Too many classes: {num_classes} (max {app.config['MAX_CLASSES']})"

    if num_classes < 2:
        return None, "Need at least 2 classes for classification"

    # Validate image paths - prevent path traversal
    def is_safe_path(p):
        p = str(p).strip()
        # No absolute paths, no parent directory references
        if os.path.isabs(p) or '..' in p:
            return False
        # Only allow safe characters
        return bool(re.match(r'^[a-zA-Z0-9_\-/\\.]+$', p))

    unsafe_paths = df[~df['image_path'].apply(is_safe_path)]
    if not unsafe_paths.empty:
        return None, "Invalid image paths detected (no absolute paths or '..' allowed)"

    # Drop rows with NaN in required columns
    df = df.dropna(subset=['image_path', 'label'])

    return df, None


def validate_image_file(filepath: str) -> bool:
    """Validate that a file is actually an image."""
    try:
        img_data = tf.io.read_file(filepath)
        # Try to decode as image
        img = tf.image.decode_image(img_data, channels=3)
        # Check dimensions are reasonable
        if img.shape[0] < 1 or img.shape[1] < 1:
            return False
        if img.shape[0] > 10000 or img.shape[1] > 10000:
            return False
        return True
    except Exception:
        return False


def load_and_preprocess_image(image_path: str, label: int) -> tuple:
    """Load and preprocess a single image."""
    img_size = app.config['IMAGE_SIZE']
    try:
        img_data = tf.io.read_file(image_path)
        img = tf.image.decode_image(img_data, channels=3, expand_animations=False)
        img = tf.image.resize(img, img_size)
        img = tf.cast(img, tf.float32) / 255.0
        # Clip to valid range
        img = tf.clip_by_value(img, 0.0, 1.0)
        return img, label
    except Exception as e:
        logger.warning(f"Failed to load image {image_path}: {e}")
        # Return a blank image as fallback
        return tf.zeros((*img_size, 3), dtype=tf.float32), label


def create_model(num_classes: int, input_shape: tuple = (128, 128, 3)) -> tf.keras.Model:
    """Create a simple image classification model."""
    model = tf.keras.Sequential([
        tf.keras.layers.InputLayer(input_shape=input_shape),
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Dropout(0.25),

        tf.keras.layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Dropout(0.25),

        tf.keras.layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        tf.keras.layers.BatchNormalization(),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Dropout(0.25),

        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dense(256, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=0.001),
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )

    return model


class TrainingPipeline:
    """Manages the training pipeline for community-contributed data."""

    def __init__(self, model_dir: str):
        self.model_dir = model_dir
        self.model = None
        self.label_mapping = {}
        self.reverse_label_mapping = {}
        self.training_history = []
        self._lock = False  # Simple lock (use threading.Lock in production)

    def _get_model_path(self, model_id: str) -> str:
        """Get safe model path."""
        safe_id = re.sub(r'[^a-zA-Z0-9_\-]', '', model_id)
        if not safe_id:
            safe_id = 'default'
        return os.path.join(self.model_dir, f"model_{safe_id}")

    def train(self, df: pd.DataFrame, image_base_dir: str,
              model_id: str = 'default', epochs: int = 10,
              batch_size: int = 32, user_id: str = 'unknown') -> dict:
        """Train or fine-tune the model with new data."""
        if self._lock:
            return {'error': 'Training already in progress'}

        self._lock = True
        try:
            # Sanitize parameters
            epochs = min(max(1, epochs), 100)
            batch_size = min(max(1, batch_size), 128)

            # Build label mapping
            unique_labels = sorted(df['label'].unique())
            self.label_mapping = {label: idx for idx, label in enumerate(unique_labels)}
            self.reverse_label_mapping = {idx: label for label, idx in self.label_mapping.items()}
            num_classes = len(unique_labels)

            # Prepare image paths and labels
            image_paths = []
            labels = []
            skipped = 0

            for _, row in df.iterrows():
                img_path = os.path.join(image_base_dir, str(row['image_path']).strip())
                # Resolve and verify path is within base directory
                resolved_path = os.path.realpath(img_path)
                resolved_base = os.path.realpath(image_base_dir)

                if not resolved_path.startswith(resolved_base):
                    logger.warning(f"Path traversal attempt: {img_path}")
                    skipped += 1
                    continue

                if not os.path.isfile(resolved_path):
                    logger.warning(f"Image not found: {resolved_path}")
                    skipped += 1
                    continue

                if not validate_image_file(resolved_path):
                    logger.warning(f"Invalid image file: {resolved_path}")
                    skipped += 1
                    continue

                image_paths.append(resolved_path)
                labels.append(self.label_mapping[row['label']])

            if len(image_paths) < 2:
                return {'error': 'Not enough valid images for training'}

            logger.info(f"Training with {len(image_paths)} images, skipped {skipped}")

            # Create TF dataset
            dataset = tf.data.Dataset.from_tensor_slices((image_paths, labels))
            dataset = dataset.map(
                lambda path, label: load_and_preprocess_image(path, label),
                num_parallel_calls=tf.data.AUTOTUNE
            )

            # Split into train/validation
            total = len(image_paths)
            val_size = max(1, int(total * 0.2))
            train_size = total - val_size

            dataset = dataset.shuffle(buffer_size=min(total, 10000), seed=42)
            train_ds = dataset.take(train_size).batch(batch_size).prefetch(tf.data.AUTOTUNE)
            val_ds = dataset.skip(train_size).batch(batch_size).prefetch(tf.data.AUTOTUNE)

            # Create or load model
            model_path = self._get_model_path(model_id)
            if os.path.exists(model_path) and self.model is not None:
                logger.info("Fine-tuning existing model")
            else:
                logger.info("Creating new model")
                self.model = create_model(
                    num_classes=num_classes,
                    input_shape=(*app.config['IMAGE_SIZE'], 3)
                )

            # Add early stopping to prevent overfitting
            callbacks = [
                tf.keras.callbacks.EarlyStopping(
                    monitor='val_loss',
                    patience=5,
                    restore_best_weights=True
                ),
                tf.keras.callbacks.ReduceLROnPlateau(
                    monitor='val_loss',
                    factor=0.5,
                    patience=3
                )
            ]

            # Train
            history = self.model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=epochs,
                callbacks=callbacks,
                verbose=1
            )

            # Save model
            self.model.save(model_path)

            # Save label mapping
            import json
            mapping_path = os.path.join(model_path, 'label_mapping.json')
            with open(mapping_path, 'w') as f:
                json.dump(self.label_mapping, f)

            # Record training event
            training_record = {
                'model_id': model_id,
                'user_id': user_id,
                'num_images': len(image_paths),
                'num_classes': num_classes,
                'epochs_completed': len(history.history['loss']),
                'final_train_accuracy': float(history.history['accuracy'][-1]),
                'final_val_accuracy': float(history.history['val_accuracy'][-1]),
                'final_train_loss': float(history.history['loss'][-1]),
                'final_val_loss': float(history.history['val_loss'][-1]),
                'skipped_images': skipped
            }
            self.training_history.append(training_record)

            return {
                'status': 'success',
                'training_summary': training_record
            }

        except Exception as e:
            logger.error(f"Training failed: {e}")
            return {'error': f'Training failed: {str(e)}'}
        finally:
            self._lock = False

    def predict(self, image_path: str, model_id: str = 'default') -> dict:
        """Make a prediction on a single image."""
        model_path = self._get_model_path(model_id)

        if self.model is None:
            if os.path.exists(model_path):
                self.model = tf.keras.models.load_model(model_path)
                # Load label mapping
                import json
                mapping_path = os.path.join(model_path, 'label_mapping.json')
                if os.path.exists(mapping_path):
                    with open(mapping_path, 'r') as f:
                        self.label_mapping = json.load(f)
                        self.reverse_label_mapping = {
                            int(v): k for k, v in self.label_mapping.items()
                        }
            else:
                return {'error': 'No trained model available'}

        if not validate_image_file(image_path):
            return {'error': 'Invalid image file'}

        try:
            img, _ = load_and_preprocess_image(image_path, 0)
            img = tf.expand_dims(img, 0)

            predictions = self.model.predict(img, verbose=0)
            predicted_class_idx = int(np.argmax(predictions[0]))
            confidence = float(predictions[0][predicted_class_idx])

            predicted_label = self.reverse_label_mapping.get(
                predicted_class_idx, f'class_{predicted_class_idx}'
            )

            # Return top-5 predictions
            top_indices = np.argsort(predictions[0])[::-1][:5]
            top_predictions = []
            for idx in top_indices:
                idx = int(idx)
                top_predictions.append({
                    'label': self.reverse_label_mapping.get(idx, f'class_{idx}'),
                    'confidence': float(predictions[0][idx])
                })

            return {
                'predicted_label': predicted_label,
                'confidence': confidence,
                'top_predictions': top_predictions
            }
        except Exception as e:
            logger.error(f"Prediction failed: {e}")
            return {'error': f'Prediction failed: {str(e)}'}


# Initialize pipeline
pipeline = TrainingPipeline(app.config['MODEL_FOLDER'])


@app.route('/api/register', methods=['POST'])
@rate_limit
def register_user():
    """Register a new user and get an API key."""
    data = request.get_json()
    if not data or 'user_id' not in data:
        return jsonify({'error': 'user_id required'}), 400

    user_id = str(data['user_id']).strip()
    if not re.match(r'^[a-zA-Z0-9_\-]{3,50}$', user_id):
        return jsonify({'error': 'Invalid user_id (alphanumeric, 3-50 chars)'}), 400

    api_key = generate_api_key(user_id)
    return jsonify({
        'api_key': api_key,
        'message': 'Store this key securely. It cannot be retrieved later.'
    }), 201


@app.route('/api/upload-csv', methods=['POST'])
@require_api_key
@rate_limit
def upload_csv():
    """Upload a CSV file with training data metadata."""
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    if not allowed_file(file.filename, app.config['ALLOWED_EXTENSIONS']):
        return jsonify({'error': 'Only CSV files are allowed'}), 400

    # Save file with unique name
    safe_name = sanitize_filename(file.filename)
    unique_name = f"{uuid.uuid4().hex}_{safe_name}"
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_name)

    try:
        file.save(filepath)

        # Validate CSV
        df, error = validate_csv_data(filepath)
        if error:
            os.remove(filepath)
            return jsonify({'error': error}), 400

        return jsonify({
            'status': 'success',
            'file_id': unique_name,
            'rows': len(df),
            'classes': df['label'].nunique(),
            'class_distribution': df['label'].value_counts().to_dict()
        }), 200

    except Exception as e:
        if os.path.exists(filepath):
            os.remove(filepath)
        logger.error(f"Upload failed: {e}")
        return jsonify({'error': 'Upload failed'}), 500


@app.route('/api/upload-images', methods=['POST'])
@require_api_key
@rate_limit
def upload_images():
    """Upload training images."""
    if 'files' not in request.files:
        return jsonify({'error': 'No files provided'}), 400

    files = request.files.getlist('files')
    if not files:
        return jsonify({'error': 'No files selected'}), 400

    # Create user-specific upload directory
    user_dir = os.path.join(
        app.config['UPLOAD_FOLDER'],
        'images',
        re.sub(r'[^a-zA-Z0-9_\-]', '', g.user_id)
    )
    os.makedirs(user_dir, exist_ok=True)

    uploaded = []
    errors = []

    for file in files:
        if not file.filename:
            continue

        if not allowed_file(file.filename, app.config['ALLOWED_IMAGE_EXTENSIONS']):
            errors.append(f"Skipped {file.filename}: invalid extension")
            continue

        safe_name = sanitize_filename(file.filename)
        unique_name = f"{uuid.uuid4().hex}_{safe_name}"
        filepath = os.path.join(user_dir, unique_name)

        try:
            file.save(filepath)

            # Validate it's actually an image
            if not validate_image_file(filepath):
                os.remove(filepath)
                errors.append(f"Skipped {file.filename}: not a valid image")
                continue

            uploaded.append(unique_name)
        except Exception as e:
            if os.path.exists(filepath):
                os.remove(filepath)
            errors.append(f"Failed to save {file.filename}")

    return jsonify({
        'status': 'success',
        'uploaded': len(uploaded),
        'files': uploaded,
        'errors': errors
    }), 200


@app.route('/api/train', methods=['POST'])
@require_api_key
@rate_limit
def train_model():
    """Start training with uploaded CSV and images."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    file_id = data.get('file_id', '')
    model_id = data.get('model_id', 'default')
    epochs = data.get('epochs', 10)
    batch_size = data.get('batch_size', 32)

    # Validate file_id
    if not re.match(r'^[a-zA-Z0-9_\-\.]+$', file_id):
        return jsonify({'error': 'Invalid file_id'}), 400

    # Validate model_id
    if not re.match(r'^[a-zA-Z0-9_\-]{1,50}$', model_id):
        return jsonify({'error': 'Invalid model_id'}), 400

    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], file_id)

    # Prevent path traversal
    if not os.path.realpath(csv_path).startswith(os.path.realpath(app.config['UPLOAD_FOLDER'])):
        return jsonify({'error': 'Invalid file path'}), 400

    if not os.path.exists(csv_path):
        return jsonify({'error': 'CSV file not found'}), 404

    # Validate CSV again
    df, error = validate_csv_data(csv_path)
    if error:
        return jsonify({'error': error}), 400

    # Determine image base directory
    image_base_dir = data.get('image_base_dir', '')
    if image_base_dir:
        # Only allow user's own image directory
        safe_user_id = re.sub(r'[^a-zA-Z0-9_\-]', '', g.user_id)
        image_base_dir = os.path.join(
            app.config['UPLOAD_FOLDER'], 'images', safe_user_id
        )
    else:
        safe_user_id = re.sub(r'[^a-zA-Z0-9_\-]', '', g.user_id)
        image_base_dir = os.path.join(
            app.config['UPLOAD_FOLDER'], 'images', safe_user_id
        )

    if not os.path.isdir(image_base_dir):
        return jsonify({'error': 'Image directory not found. Upload images first.'}), 404

    # Train
    result = pipeline.train(
        df=df,
        image_base_dir=image_base_dir,
        model_id=model_id,
        epochs=epochs,
        batch_size=batch_size,
        user_id=g.user_id
    )

    if 'error' in result:
        return jsonify(result), 400

    return jsonify(result), 200


@app.route('/api/contribute', methods=['POST'])
@require_api_key
@rate_limit
def contribute_example():
    """Contribute a single labeled training example."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    label = request.form.get('label', '').strip()
    if not label or not re.match(r'^[a-zA-Z0-9_\-\s]{1,100}$', label):
        return jsonify({'error': 'Invalid label'}), 400

    file = request.files['image']
    if not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    if not allowed_file(file.filename, app.config['ALLOWED_IMAGE_EXTENSIONS']):
        return jsonify({'error': 'Invalid image format'}), 400

    # Save to contributions directory
    safe_user_id = re.sub(r'[^a-zA-Z0-9_\-]', '', g.user_id)
    contrib_dir = os.path.join(
        app.config['UPLOAD_FOLDER'], 'contributions', safe_user_id
    )
    os.makedirs(contrib_dir, exist_ok=True)

    safe_name = sanitize_filename(file.filename)
    unique_name = f"{uuid.uuid4().hex}_{safe_name}"
    filepath = os.path.join(contrib_dir, unique_name)

    try:
        file.save(filepath)

        if not validate_image_file(filepath):
            os.remove(filepath)
            return jsonify({'error': 'Invalid image file'}), 400

        # Append to contributions CSV
        contrib_csv = os.path.join(contrib_dir, 'contributions.csv')
        new_row = pd.DataFrame([{
            'image_path': unique_name,
            'label': label,
            'contributor': g.user_id
        }])

        if os.path.exists(contrib_csv):
            existing = pd.read_csv(contrib_csv, nrows=app.config['MAX_ROWS_PER_CSV'])
            if len(existing) >= app.config['MAX_ROWS_PER_CSV']:
                os.remove(filepath)
                return jsonify({'error': 'Contribution limit reached'}), 400
            combined = pd.concat([existing, new_row], ignore_index=True)
        else:
            combined = new_row

        combined.to_csv(contrib_csv, index=False)

        return jsonify({
            'status': 'success',
            'message': 'Contribution accepted',
            'image_id': unique_name,
            'label': label,
            'total_contributions': len(combined)
        }), 201

    except Exception as e:
        if os.path.exists(filepath):
            os.remove(filepath)
        logger.error(f"Contribution failed: {e}")
        return jsonify({'error': 'Contribution failed'}), 500


@app.route('/api/predict', methods=['POST'])
@require_api_key
@rate_limit
def predict():
    """Make a prediction on an uploaded image."""
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    model_id = request.form.get('model_id', 'default')
    if not re.match(r'^[a-zA-Z0-9_\-]{1,50}$', model_id):
        return jsonify({'error': 'Invalid model_id'}), 400

    file = request.files['image']
    if not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    if not allowed_file(file.filename, app.config['ALLOWED_IMAGE_EXTENSIONS']):
        return jsonify({'error': 'Invalid image format'}), 400

    # Save temporarily
    safe_name = sanitize_filename(file.filename)
    unique_name = f"{uuid.uuid4().hex}_{safe_name}"
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], 'temp', unique_name)
    os.makedirs(os.path.dirname(filepath), exist_ok=True)

    try:
        file.save(filepath)

        if not validate_image_file(filepath):
            return jsonify({'error': 'Invalid image file'}), 400

        result = pipeline.predict(filepath, model_id)

        if 'error' in result:
            return jsonify(result), 400

        return jsonify(result), 200

    except Exception as e:
        logger.error(f"Prediction failed: {e}")
        return jsonify({'error': 'Prediction failed'}), 500
    finally:
        if os.path.exists(filepath):
            os.remove(filepath)


@app.route('/api/model-info', methods=['GET'])
@require_api_key
@rate_limit
def model_info():
    """Get information about training history."""
    model_id = request.args.get('model_id', 'default')
    if not re.match(r'^[a-zA-Z0-9_\-]{1,50}$', model_id):
        return jsonify({'error': 'Invalid model_id'}), 400

    history = [
        h for h in pipeline.training_history
        if h['model_id'] == model_id
    ]

    model_path = pipeline._get_model_path(model_id)
    model_exists = os.path.exists(model_path)

    return jsonify({
        'model_id': model_id,
        'model_exists': model_exists,
        'training_runs': len(history),
        'history': history[-10:],  # Last 10 training runs
        'label_mapping': pipeline.label_mapping if model_exists else {}
    }), 200


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    return jsonify({'status': 'healthy'}), 200


